unsigned int count_set_bits(unsigned int n) {
    unsigned int count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}

lean_translation:
def count_set_bits (n : Nat) : Nat :=
  if h : n = 0 then 0
  else (n % 2) + count_set_bits (n / 2)
termination_by n
decreasing_by exact Nat.div_lt_self (Nat.pos_of_ne_zero h) (by omega)

tests:
