unsigned int next_power_of_two(unsigned int n) {
    if (n == 0) return 1;
    n--;
    n |= n >> 1;
    n |= n >> 2;
    n |= n >> 4;
    n |= n >> 8;
    n |= n >> 16;
    return n + 1;
}

lean_translation:
def next_power_of_two (n : Nat) : Nat :=
  if n = 0 then 1
  else
    let rec go (p : Nat) : Nat :=
      if p >= n then p else go (p * 2)
    go 1

tests:
