unsigned int lowest_set_bit(unsigned int n) {
    return n & (~n + 1);
}

lean_translation:
def lowest_set_bit (n : Nat) : Nat :=
  if h : n = 0 then 0
  else if n % 2 = 1 then 1
  else 2 * lowest_set_bit (n / 2)
termination_by n
decreasing_by exact Nat.div_lt_self (Nat.pos_of_ne_zero h) (by omega)

tests:
